                    if subclass and len(subclass) >= 3:
                        cpc_codes.append(subclass)
            # Remove duplicates
            cal_pub_to_cpc[pub_num] = list(dict.fromkeys(cpc_codes))
        except:
            cal_pub_to_cpc[pub_num] = []
    else:
        cal_pub_to_cpc[pub_num] = []

print('__RESULT__:')
print(json.dumps({
    'california_pubs': len(cal_pub_numbers),
